class BoundedList:
    def __init__(self, max_size):
        self._data = []
        self._max = max_size
    def __len__(self):
        return len(self._data)
    def __getitem__(self, idx):
        return self._data[idx]
    def append(self, item):
        if len(self) >= self._max:
            raise OverflowError
        self._data.append(item)

